// Parse the Claude response and merge it with the original lead fields
const lead = $('Set Lead Fields').item.json;
const raw = $json.content?.[0]?.text || '{}';

let parsed = {
  lead_type: 'unknown',
  summary: 'Failed to parse AI response',
  score: 0,
  is_ready: false,
  timeline_band: 'exploring',
  financing_ready: false,
  recommended_agent_role: 'Intake review',
  suggested_next_step: 'Review manually',
  missing_info: []
};

try {
  const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  parsed = JSON.parse(cleaned);
  parsed.score = Math.max(1, Math.min(10, parseInt(parsed.score, 10) || 0));
} catch (e) {
  parsed.summary = 'AI returned malformed JSON: ' + raw.slice(0, 200);
}

const isReady = parsed.is_ready === true || parsed.score >= 7;
const missingInfo = Array.isArray(parsed.missing_info) ? parsed.missing_info.join(' | ') : '';

return [{
  json: {
    ...lead,
    lead_type: parsed.lead_type || 'unknown',
    summary: parsed.summary || '',
    score: parsed.score,
    is_ready: isReady,
    isReady,
    timeline_band: parsed.timeline_band || 'exploring',
    financing_ready: parsed.financing_ready === true,
    recommended_agent_role: parsed.recommended_agent_role || 'Intake review',
    suggested_next_step: parsed.suggested_next_step || '',
    missing_info: missingInfo
  }
}];
